targets.expr:
histogram_quantile(0.99, 
  sum by (le) (
    rate(traces_spanmetrics_latency_bucket{
      k8s_cluster_name="$cluster",
      span_kind="SPAN_KIND_SERVER", 
      service_name="$apps"
    }[$__rate_interval])
  )
)

histogram_quantile(0.95, 
  sum by (le) (
    rate(traces_spanmetrics_latency_bucket{
      span_kind="SPAN_KIND_SERVER", 
      service_name="$apps"
    }[$__rate_interval])
  )
)

histogram_quantile(0.95, 
  sum by (le) (
    rate(traces_spanmetrics_latency_bucket{
      k8s_cluster_name="$env",
      span_kind="SPAN_KIND_SERVER", 
      service_name="$apps"
    }[$__rate_interval] offset 1w)
  )
)

(
      sum by (service_name, service_namespace) (
        rate(traces_spanmetrics_calls_total{k8s_cluster_name="$cluster", span_kind="SPAN_KIND_CLIENT", server_address=~"$apps[.:].*"}[$__rate_interval])
      ) or vector(0)
      +
      sum by (service_name, service_namespace) (
        rate(traces_spanmetrics_calls_total{k8s_cluster_name="$cluster", span_kind="SPAN_KIND_CLIENT", http_host=~"$apps[.:].*"}[$__rate_interval])
      ) or vector(0)
    )

(
      sum by (service_name, service_namespace) (
        rate(traces_spanmetrics_calls_total{k8s_cluster_name="$cluster", status_code="STATUS_CODE_ERROR",span_kind="SPAN_KIND_CLIENT", server_address=~"$apps[.:].*"}[$__rate_interval])
      ) or vector(0)
      +
      sum by (service_name, service_namespace) (
        rate(traces_spanmetrics_calls_total{k8s_cluster_name="$cluster", status_code="STATUS_CODE_ERROR",span_kind="SPAN_KIND_CLIENT", http_host=~"$apps[.:].*"}[$__rate_interval])
      ) or vector(0)
    )

sum by (address, system) (
    label_replace(
      label_replace(
        label_replace(
          label_replace(
            rate(traces_spanmetrics_calls_total{k8s_cluster_name="$cluster", span_kind=~"SPAN_KIND_(CLIENT|CONSUMER)", service_name="$apps"}[$__rate_interval]),
            "address", "$1", "http_host", "(.+)"
          ),
          "address", "$1", "server_address", "(.+)"
        ),
        "system", "$1", "db_system", "(.+)"
      ),
      "system", "$1", "messaging_system", "(.+)"
    )
)

sum by (address, system) (
    label_replace(
      label_replace(
        label_replace(
          label_replace(
            rate(traces_spanmetrics_calls_total{k8s_cluster_name="$cluster", status_code="STATUS_CODE_ERROR", span_kind=~"SPAN_KIND_(CLIENT|CONSUMER)", service_name="$apps"}[$__rate_interval]),
            "address", "$1", "http_host", "(.+)"
          ),
          "address", "$1", "server_address", "(.+)"
        ),
        "system", "$1", "db_system", "(.+)"
      ),
      "system", "$1", "messaging_system", "(.+)"
    )
)
